mapper.select:
SELECT c.id, c.item_id, i.title AS item_title, i.owner_type AS item_owner_type, c.claimer_id, claimer.real_name AS claimer_name, i.user_id AS owner_id, owner.real_name AS owner_name, c.reason, c.status, c.admin_note, c.created_at, c.reviewed_at FROM item_claim c LEFT JOIN lost_found_item i ON c.item_id = i.id LEFT JOIN sys_user claimer ON c.claimer_id = claimer.id LEFT JOIN sys_user owner ON i.user_id = owner.id
AND c.status = #{status} AND c.item_id = #{itemId}
ORDER BY c.created_at DESC
